class Solution:
    def getPermutation(self, n, k):
        import math
        digits = [str(d) for d in range(1, n + 1)]
        k -= 1
        res = []
        for i in range(n, 0, -1):
            f = math.factorial(i - 1)
            idx = k // f
            res.append(digits.pop(idx))
            k %= f
        return ''.join(res)

