var getPermutation = function(n, k) {
    const fact = [1];
    for (let i = 1; i <= n; i++) fact[i] = fact[i - 1] * i;
    const digits = [];
    for (let d = 1; d <= n; d++) digits.push(String(d));
    k -= 1;
    const res = [];
    for (let i = n; i >= 1; i--) {
        const f = fact[i - 1];
        const idx = Math.floor(k / f);
        res.push(digits.splice(idx, 1)[0]);
        k %= f;
    }
    return res.join('');
};
